+		OriginalType: "task",
+	}
+
+	// Expired tombstone (older than TTL)
+	expiredTombstone := Issue{
+		ID:           "bd-abc123",
+		Title:        "Original title",
+		Status:       StatusTombstone,
+		Priority:     2,
+		CreatedAt:    "2024-01-01T00:00:00Z",
