+		DeletedBy:    "user2",
+		DeleteReason: "Duplicate issue",
+		OriginalType: "task",
+	}
+
+	// Modified live issue
+	modifiedLive := Issue{
+		ID:        "bd-abc123",
+		Title:     "Updated title",
+		Status:    "in_progress",
+		Priority:  1,
+		CreatedAt: "2024-01-01T00:00:00Z",
+		UpdatedAt: "2024-01-03T00:00:00Z",
+		CreatedBy: "user1",
